import React, { useEffect, useRef } from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>ENTER STOCK</p>;
  }

  const arrow = stockData.change > 0 ? '\u25B2' : '\u25BC';
  const mp = stockData.change > 0 ? '\x2b' : '\u2212';
  const isStockUp = stockData.change > 0;
  const Change = Math.abs(stockData.change);

  return (
    <div className='info'>
      <div>
        <p style={{color: isStockUp ? "lightgreen" : "red"}}>{stockData.symbol}</p>
        <p style={{color: isStockUp ? "lightgreen" : "red"}}>{stockData.price}</p>
      </div>
      <div>
        <p style={{color: isStockUp ? "lightgreen" : "red"}}>{arrow}{stockData.pChange}</p>
        <p style={{color: isStockUp ? "lightgreen" : "red"}}>&thinsp;{mp}&thinsp;{Change}</p>
      </div>
    </div>
  );
}

function Stock({ stockData, numStocks }) {
  const containerRef = useRef(null);
  const stocksRef = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    const stocks = stocksRef.current;

    let totalWidth = 0;
    stocks.forEach(stock => {
      totalWidth += stock.offsetWidth;
    });

    let currentPosition = 0;
    let isMovingRight = false;
    let containerWidth = container.offsetWidth;

    function moveStocks() {
      if (currentPosition > -totalWidth && isMovingRight) {
        currentPosition--;
        container.style.transform = `translateX(${currentPosition}px)`;
        requestAnimationFrame(moveStocks);
      } else if (currentPosition < 0 && !isMovingRight) {
        currentPosition++;
        container.style.transform = `translateX(${currentPosition}px)`;
        requestAnimationFrame(moveStocks);
      } else {
        if (totalWidth > containerWidth) {
          isMovingRight = !isMovingRight;
          requestAnimationFrame(moveStocks);
        } else {
          let extraSpace = containerWidth - totalWidth;
          container.style.transform = `translateX(${extraSpace / 2}px)`;
        }
      }
    }

    moveStocks();
  }, [numStocks]);

  return (
    <div className='info-container' ref={containerRef}>
      {[...Array(numStocks)].map((_, index) => (
        <div key={index} className='info' ref={stocksRef}>
          <DisplayStockData stockData={stockData} />
        </div>
      ))}
    </div>
  );
}

export default Stock;
